return items.map(item => {
  let raw = item.json.output;

  if (!raw) {
    return { json: {} };
  }

  // 1. Убираем ```json и ```
  raw = raw.replace(/^```json\s*/, '').replace(/\s*```$/, '');

  let data;
  try {
    // 2. Парсим JSON из строки
    data = JSON.parse(raw);
  } catch (error) {
    throw new Error('Ошибка парсинга JSON: ' + error.message + '\nСтрока: ' + raw.slice(0, 200));
  }

  // 3. Форматируем и создаём бинарник
  const jsonString = JSON.stringify(data, null, 2);
  const binaryData = Buffer.from(jsonString, 'utf8');

  return {
    json: {}, // json можно оставить пустым
    binary: {
      data: {
        data: binaryData.toString('base64'),
        mimeType: 'application/json',
        fileName: 'workflow.json',
      }
    }
  };
});

// Берём строку из input
let raw = $json.output;

// Убираем обёртку ```json ... ```
raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();

// Парсим JSON
const parsed = JSON.parse(raw);

// Возвращаем валидный объект
return [{ json: parsed }];

try {
    const workflow = $items()[0].json;

    // Создаём словарь id -> name
    const idToName = {};
    workflow.elements.forEach(el => {
        idToName[el.id] = el.name || el.id;
    });

    // Функция для замены id и parent
    const replaceIds = (el) => {
        return {
            ...el,
            id: el.name || el.id,
            parent: el.parent ? (idToName[el.parent] || el.parent) : null
        };
    };

    // Проходим несколько раз, чтобы заменить parent, если родитель сам менялся
    let newElements = workflow.elements.map(replaceIds);
    let changed = true;
    while (changed) {
        changed = false;
        newElements = newElements.map(el => {
            const newParent = el.parent ? (idToName[el.parent] || el.parent) : null;
            if (newParent !== el.parent) changed = true;
            return { ...el, parent: newParent };
        });
    }

    // Заменяем source и target на имя в connections
    const newConnections = workflow.connections.map(conn => ({
        source: idToName[conn.source] || conn.source,
        target: idToName[conn.target] || conn.target,
        condition: conn.condition
    }));

    return [{
        json: {
            elements: newElements,
            connections: newConnections
        }
    }];

} catch (error) {
    return [{
        json: {
            error: error.message
        }
    }];
}

