  row_number: Math.floor(Math.random() * 100) + 1
};

return [{
  json: tableData
}];

// Анализ гео публикации и определение вилки зарплаты
const locations = ['Москва', 'Санкт-Петербург', 'Удаленно'];
const selectedLocation = locations[Math.floor(Math.random() * locations.length)];

const salaryRanges = {
  'Москва': { min: 150000, max: 250000 },
  'Санкт-Петербург': { min: 120000, max: 200000 },
  'Удаленно': { min: 100000, max: 180000 }
};

const analysis = {
  location: selectedLocation,
  salary_range: salaryRanges[selectedLocation],
  currency: 'RUB',
  competitors_count: Math.floor(Math.random() * 50) + 10,
  recommended_publish: true
};

return [{
  json: { ...($input.first().json), analysis }
}];

// Исправление вакансии вручную
const correctedVacancy = {
  ...$input.first().json,
  status: 'manually_corrected',
