}];

// Отправка отчета
const finalReport = {
  ...($input.first().json),
  sent_to: ['manager@company.com', 'hr@company.com'],
  sent_at: new Date().toISOString(),
  status: 'sent'
};

return [{
  json: finalReport
}];

